from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Group triples by subject
    subject_data = {}
    for triple in triples:
        if triple.subject not in subject_data:
            subject_data[triple.subject] = []
        subject_data[triple.subject].append(triple)

    sentences = []

    # Process each subject's triples
    for subject, subject_triples in subject_data.items():
        parts = []

        # Categorize predicates for better sentence construction
        personal_info = []
        mission_info = []
        award_info = []
        other_info = []

        for triple in subject_triples:
            pred = triple.predicate
            obj = triple.object

            if pred in ['birthDate', 'birthName', 'birthPlace', 'deathDate', 'deathPlace', 'nationality', 'alternativeName', 'occupation', 'status', 'selectedByNasa', 'dateOfRetirement', 'timeInSpace', 'almaMater']:
                personal_info.append((pred, obj))
            elif pred in ['mission', 'operator', 'backupPilot', 'commander', 'crewMembers', 'cosparId']:
                mission_info.append((pred, obj))
            elif pred in ['awards', 'award', 'ribbonAward']:
                award_info.append((pred, obj))
            else:
                other_info.append((pred, obj))

        # Build sentence for this subject
        if personal_info:
            first_part = f"{subject}"
            if any(p[0] == 'birthName' for p in personal_info):
                birth_name = next((p[1] for p in personal_info if p[0] == 'birthName'), None)
                if birth_name:
                    first_part = f"{subject} (born {birth_name})"

            details = []
            for pred, obj in personal_info:
                if pred == 'birthDate':
                    details.append(f"born on {obj}")
                elif pred == 'birthPlace':
                    details.append(f"born in {obj}")
                elif pred == 'deathDate':
                    details.append(f"passed away on {obj}")
                elif pred == 'deathPlace':
                    details.append(f"died in {obj}")
                elif pred == 'nationality':
                    details.append(f"of {obj}")
                elif pred == 'occupation':
                    details.append(f"who worked as a {obj}")
                elif pred == 'almaMater':
                    details.append(f"educated at {obj}")
                elif pred == 'selectedByNasa':
                    details.append(f"selected by NASA in {obj}")
                elif pred == 'timeInSpace':
                    details.append(f"spent {float(obj)/60:.1f} hours in space")
                elif pred == 'status':
                    details.append(f"currently {obj}")

            if details:
                parts.append(f"{first_part}, {', '.join(details)}")

        if mission_info:
            mission_parts = []
            for pred, obj in mission_info:
                if pred == 'mission':
                    mission_parts.append(f"participated in the {obj} mission")
                elif pred == 'commander':
                    mission_parts.append(f"commanded by {obj}")
                elif pred == 'crewMembers':
                    mission_parts.append(f"with crew member {obj}")
                elif pred == 'backupPilot':
                    mission_parts.append(f"with backup pilot {obj}")
                elif pred == 'operator':
                    mission_parts.append(f"operated by {obj}")
            if mission_parts:
                parts.append(f"who {' and '.join(mission_parts)}")

        if award_info:
            award_parts = []
            for pred, obj in award_info:
                if pred == 'awards':
                    award_parts.append(f"received {obj} awards")
                elif pred == 'award':
                    award_parts.append(f"earned the {obj}")
                elif pred == 'ribbonAward':
                    award_parts.append(f"with {obj} ribbon")
            if award_parts:
                parts.append(f"and {' and '.join(award_parts)}")

        if other_info:
            other_parts = []
            for pred, obj in other_info:
                if pred == 'title':
                    other_parts.append(f"held the title of {obj}")
                elif pred == 'servedAsChiefOfTheAstronautOfficeIn':
                    other_parts.append(f"served as Chief of the Astronaut Office in {obj}")
            if other_parts:
                parts.append(f"who {' and '.join(other_parts)}")

        if parts:
            sentence = " ".join(parts)
            if not sentence.endswith('.'):
                sentence += "."
            sentences.append(sentence)

    return " ".join(sentences)

# EVOLVE-BLOCK-END
